/* Lightweight fallback shim for SheetJS API surface used by this extension.
 * For full XLS/XLSX support, replace this file with the official SheetJS build.
 */
(function (global) {
  function decode(buffer) {
    return new TextDecoder('utf-8').decode(buffer);
  }

  function parseDelimited(text) {
    const lines = text.split(/\r?\n/).filter(Boolean);
    if (!lines.length) return [];
    const delimiter = lines[0].includes('\t') ? '\t' : ',';
    const headers = lines[0].split(delimiter).map((h) => h.trim());

    return lines.slice(1).map((line) => {
      const values = line.split(delimiter);
      const out = {};
      headers.forEach((header, idx) => {
        out[header] = (values[idx] || '').trim();
      });
      return out;
    });
  }

  global.XLSX = {
    read(data, opts) {
      if (!opts || opts.type !== 'array') {
        throw new Error('This bundled XLSX shim only supports array input.');
      }
      const text = decode(data);
      return {
        SheetNames: ['Sheet1'],
        Sheets: {
          Sheet1: {
            __rows: parseDelimited(text)
          }
        }
      };
    },
    utils: {
      sheet_to_json(sheet) {
        return sheet.__rows || [];
      }
    }
  };
})(window);
